+export fn zero_f32(ptr: [*]f32, n: u32) void {
+    const nz: usize = n;
+    const LANES: usize = 4;
+    const zero_vec: @Vector(4, f32) = @splat(0.0);
+    var i: usize = 0;
+    while (i + LANES <= nz) : (i += LANES) {
+        ptr[i ..][0..LANES].* = zero_vec;
+    }
+    while (i < nz) : (i += 1) ptr[i] = 0.0;
+}
